      }
      return res.json(candidateResult.rows[0]);
    }

    res.json(result.rows[0]);
  } catch (err) {
    console.error('Error fetching offer letter:', err);
    res.status(500).json({ error: 'Failed to fetch offer letter' });
  }
});

// Get all offers for recruiter's company
