    const { checklist_id, step, data } = req.body;

    // Verify checklist belongs to this candidate
    const checklist = await pool.query(
      'SELECT * FROM onboarding_checklists WHERE id = $1 AND candidate_id = $2',
      [checklist_id, req.user.id]
    );
